using Financeiro.Domain.Entities; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders;
namespace Financeiro.Infrastructure.Persistence.Configurations; public class UsuarioConfiguration : IEntityTypeConfiguration<Usuario>{ public void Configure(EntityTypeBuilder<Usuario> b){ b.ToTable("usuarios"); b.HasKey(x=>x.Id); b.Property(x=>x.Nome).HasColumnName("nome").HasMaxLength(150).IsRequired(); b.Property(x=>x.Email).HasColumnName("email").HasMaxLength(150).IsRequired(); b.Property(x=>x.PasswordHash).HasColumnName("password_hash").HasMaxLength(128).IsRequired(); b.Property(x=>x.Role).HasColumnName("role").HasMaxLength(50).IsRequired(); b.Property(x=>x.Ativo).HasColumnName("ativo").IsRequired(); b.Property(x=>x.CreatedAt).HasColumnName("created_at").IsRequired(); b.Property(x=>x.UpdatedAt).HasColumnName("updated_at"); b.HasIndex(x=>x.Email).IsUnique(); } }
